-- Add German A1 lesson 7: 20 short sentences and 20 three-option sentence quizzes.
-- Four sentences intentionally review prior examples; sixteen sentences introduce new content (80%).

begin;

update language_cards_category_translations set description = case lang_code
  when 'de' then 'Der A1-Einstieg: Worte, Menschen, Zahlen, Zeit, Farben, Essen, Artikel und erste ganze Sätze.'
  when 'en' then 'The A1 foundation: words, people, numbers, time, colors, food, articles, and first complete sentences.'
  else description end
where category_id = '8e6bb6a0-7a01-4f8f-b4cd-dc7ba4ebbb2d' and lang_code in ('de','en');

update language_cards_learning_course_translations set description = case lang_code
  when 'de' then 'Alles Wichtige für den Einstieg – jetzt auch mit kurzen ganzen Sätzen.'
  when 'en' then 'The essential beginner foundation, now including short complete sentences.'
  else description end
where course_id = 'e1fd8982-b00c-4d1a-a1a0-50e2ce6b0df4' and lang_code in ('de','en');

values ('21956ad1-bba8-5b61-97b7-e947eb1e7d89', 'e1fd8982-b00c-4d1a-a1a0-50e2ce6b0df4', 'de-a1-basics-simple-sentences', 7, true, 'active')
on conflict (course_id, slug) do update set sort_order=excluded.sort_order, is_active=excluded.is_active, status=excluded.status;

on conflict (lesson_id, lang_code) do update set title=excluded.title, description=excluded.description;

values ('06868e48-13de-5211-97a3-f28161ba5de1', '8e6bb6a0-7a01-4f8f-b4cd-dc7ba4ebbb2d', 'de-a1-basics-simple-sentences', 7, array['swipe']::text[], true, 'active')
on conflict (category_id, slug) do update set sort_order=excluded.sort_order, game_modes=excluded.game_modes, is_active=excluded.is_active, status=excluded.status;

on conflict (practice_group_id, lang_code) do update set name=excluded.name;

on conflict (id) do update set slug=excluded.slug, card_type=excluded.card_type, native=excluded.native, transliteration=excluded.transliteration, word_type=excluded.word_type, example_native=excluded.example_native, example_transliteration=excluded.example_transliteration, context=excluded.context, difficulty=excluded.difficulty, content_md=excluded.content_md, audio_url=excluded.audio_url, image_url=excluded.image_url, image_id=excluded.image_id, sort_order=excluded.sort_order, is_active=excluded.is_active, data=excluded.data;

on conflict (card_id, lang_code) do update set translation=excluded.translation, example_translation=excluded.example_translation, hint=excluded.hint;

delete from language_cards_learning_lesson_cards where lesson_id = '21956ad1-bba8-5b61-97b7-e947eb1e7d89';

delete from language_cards_practice_group_cards where practice_group_id = '06868e48-13de-5211-97a3-f28161ba5de1';

commit;
