insert into language_cards_card_translations (card_id, lang_code, translation, example_translation, hint) values
  ('29599913-324b-53b0-ac60-b5491f5234e8', 'de', 'Ich trinke Wasser.', 'I drink water.', 'Bekannt: Ich + Verb + Objekt. Wasser und trinken kennst du schon.'),
  ('29599913-324b-53b0-ac60-b5491f5234e8', 'en', 'I drink water.', 'Ich trinke Wasser.', 'Bekannt: Ich + Verb + Objekt. Wasser und trinken kennst du schon.'),
  ('d801b121-d2d4-5569-9a40-39f330426e4c', 'de', 'Der Apfel ist rot.', 'The apple is red.', 'Bekannt: Artikel + Nomen + ist + Farbe.'),
  ('d801b121-d2d4-5569-9a40-39f330426e4c', 'en', 'The apple is red.', 'Der Apfel ist rot.', 'Bekannt: Artikel + Nomen + ist + Farbe.'),
  ('25ab5666-031c-572f-92f0-669c0ee96d6a', 'de', 'Die Katze schläft.', 'The cat is sleeping.', 'Bekanntes Beispiel: Die Katze + Verb.'),
  ('25ab5666-031c-572f-92f0-669c0ee96d6a', 'en', 'The cat is sleeping.', 'Die Katze schläft.', 'Bekanntes Beispiel: Die Katze + Verb.'),
  ('880d8699-f072-54fe-b989-1381d5f59925', 'de', 'Die Tür ist offen.', 'The door is open.', 'Bekanntes Beispiel mit die und ist.'),
  ('880d8699-f072-54fe-b989-1381d5f59925', 'en', 'The door is open.', 'Die Tür ist offen.', 'Bekanntes Beispiel mit die und ist.'),
  ('c8dcc459-3c3f-5bb1-b992-1e30458bec59', 'de', 'Ich wohne in Berlin.', 'I live in Berlin.', 'Neu: wohnen = an einem Ort leben. Orte stehen oft nach in.'),
  ('c8dcc459-3c3f-5bb1-b992-1e30458bec59', 'en', 'I live in Berlin.', 'Ich wohne in Berlin.', 'Neu: wohnen = an einem Ort leben. Orte stehen oft nach in.'),
  ('852e6cff-a99f-51ee-9624-3d02bcc1e0b6', 'de', 'Du lernst Deutsch.', 'You are learning German.', 'Neu: lernen. Bei du bekommt das Verb oft -st: du lernst.'),
  ('852e6cff-a99f-51ee-9624-3d02bcc1e0b6', 'en', 'You are learning German.', 'Du lernst Deutsch.', 'Neu: lernen. Bei du bekommt das Verb oft -st: du lernst.'),
  ('c8e23a87-0830-5c9e-9ef8-12b7d501e521', 'de', 'Er arbeitet heute.', 'He works today.', 'Neu: arbeiten = work. heute kennst du bereits.'),
  ('c8e23a87-0830-5c9e-9ef8-12b7d501e521', 'en', 'He works today.', 'Er arbeitet heute.', 'Neu: arbeiten = work. heute kennst du bereits.'),
  ('36959e87-88af-56a0-ae9e-b08ce95dbeb0', 'de', 'Sie kommt aus Japan.', 'She comes from Japan.', 'Neu: aus + Land sagt, woher jemand kommt.'),
  ('36959e87-88af-56a0-ae9e-b08ce95dbeb0', 'en', 'She comes from Japan.', 'Sie kommt aus Japan.', 'Neu: aus + Land sagt, woher jemand kommt.'),
  ('8ee704c9-c7be-502c-b97b-6bb28abebca3', 'de', 'Wir gehen zur Schule.', 'We go to school.', 'Neu: gehen = go. zur Schule bedeutet to school.'),
  ('8ee704c9-c7be-502c-b97b-6bb28abebca3', 'en', 'We go to school.', 'Wir gehen zur Schule.', 'Neu: gehen = go. zur Schule bedeutet to school.'),
  ('1f937f7d-25c3-5ab9-9779-a1fb5123379c', 'de', 'Ich kaufe Brot.', 'I buy bread.', 'Neu: kaufen = buy. Brot kennst du schon.'),
  ('1f937f7d-25c3-5ab9-9779-a1fb5123379c', 'en', 'I buy bread.', 'Ich kaufe Brot.', 'Neu: kaufen = buy. Brot kennst du schon.'),
  ('c7d981df-e7ea-5016-8480-da53bfb0c2a2', 'de', 'Du isst eine Suppe.', 'You eat a soup.', 'Neu: essen wird bei du zu du isst. Die Suppe wird hier eine Suppe.'),
  ('c7d981df-e7ea-5016-8480-da53bfb0c2a2', 'en', 'You eat a soup.', 'Du isst eine Suppe.', 'Neu: essen wird bei du zu du isst. Die Suppe wird hier eine Suppe.'),
  ('20ca7a1c-9005-519e-869d-0f7b7ecf0b1c', 'de', 'Das Kind spielt im Park.', 'The child plays in the park.', 'Neu: im bedeutet in dem. Kind und Park kennst du schon.'),
  ('20ca7a1c-9005-519e-869d-0f7b7ecf0b1c', 'en', 'The child plays in the park.', 'Das Kind spielt im Park.', 'Neu: im bedeutet in dem. Kind und Park kennst du schon.'),
  ('3dab99bf-3477-5b51-84db-322bc382e911', 'de', 'Der Hund läuft schnell.', 'The dog runs fast.', 'Neu: laufen = run. Er läuft ist die Form für er/der Hund.'),
  ('3dab99bf-3477-5b51-84db-322bc382e911', 'en', 'The dog runs fast.', 'Der Hund läuft schnell.', 'Neu: laufen = run. Er läuft ist die Form für er/der Hund.'),
  ('62dffd73-7531-5297-afda-d0dd63fda403', 'de', 'Die Mutter liest ein Buch.', 'The mother reads a book.', 'Neu: lesen wird zu sie liest. Buch ist hier ein Buch.'),
  ('62dffd73-7531-5297-afda-d0dd63fda403', 'en', 'The mother reads a book.', 'Die Mutter liest ein Buch.', 'Neu: lesen wird zu sie liest. Buch ist hier ein Buch.'),
  ('486df682-05b1-50e6-b4ea-d5d93769baad', 'de', 'Der Vater fährt mit dem Auto.', 'The father goes by car.', 'Neu: mit dem Auto = by car. fahren wird zu er fährt.'),
  ('486df682-05b1-50e6-b4ea-d5d93769baad', 'en', 'The father goes by car.', 'Der Vater fährt mit dem Auto.', 'Neu: mit dem Auto = by car. fahren wird zu er fährt.'),
  ('79b11d86-b239-5391-b89e-5387c99275c8', 'de', 'Meine Freundin hat ein Fahrrad.', 'My friend has a bicycle.', 'Neu: meine = my. Sie hat entspricht dem bekannten du hast.'),
  ('79b11d86-b239-5391-b89e-5387c99275c8', 'en', 'My friend has a bicycle.', 'Meine Freundin hat ein Fahrrad.', 'Neu: meine = my. Sie hat entspricht dem bekannten du hast.'),
  ('65701f18-eafc-5706-b1d1-a97e9a827e95', 'de', 'Das Zimmer ist sauber.', 'The room is clean.', 'Neuer Satz aus bekannten Wörtern: das Zimmer + ist + sauber.'),
  ('65701f18-eafc-5706-b1d1-a97e9a827e95', 'en', 'The room is clean.', 'Das Zimmer ist sauber.', 'Neuer Satz aus bekannten Wörtern: das Zimmer + ist + sauber.'),
  ('36ad0f3f-3515-594f-8bac-8d13f2edc876', 'de', 'Der Kaffee ist heiß.', 'The coffee is hot.', 'Neuer Satz: Kaffee kennst du, heiß kennst du von Tee und Suppe.'),
  ('36ad0f3f-3515-594f-8bac-8d13f2edc876', 'en', 'The coffee is hot.', 'Der Kaffee ist heiß.', 'Neuer Satz: Kaffee kennst du, heiß kennst du von Tee und Suppe.'),
  ('e265c091-6721-5189-8997-7739e517b347', 'de', 'Morgen trinke ich Kaffee.', 'Tomorrow I drink coffee.', 'Neu: Steht morgen zuerst, kommt das Verb trotzdem an Position zwei.'),
  ('e265c091-6721-5189-8997-7739e517b347', 'en', 'Tomorrow I drink coffee.', 'Morgen trinke ich Kaffee.', 'Neu: Steht morgen zuerst, kommt das Verb trotzdem an Position zwei.'),
  ('2675d78b-41dc-58af-a3f0-ed57332903cf', 'de', 'Am Montag arbeite ich.', 'On Monday I work.', 'Neu: am + Wochentag. Auch hier steht das Verb an Position zwei.'),
  ('2675d78b-41dc-58af-a3f0-ed57332903cf', 'en', 'On Monday I work.', 'Am Montag arbeite ich.', 'Neu: am + Wochentag. Auch hier steht das Verb an Position zwei.')
